var _dbInited = false;
var _dbInitRetryAt = 0;
async function ensureDb(env) {
  const now = Date.now();
  if (_dbInited) return;
  if (_dbInitRetryAt && now - _dbInitRetryAt < 3e4) return;
  _dbInited = true;
  _dbInitRetryAt = 0;
  try {
    initDb(env).catch((e) => {
      _dbInited = false;
      _dbInitRetryAt = Date.now();
      console.error("[initDb background] error:", e?.message || e);
    });
  } catch (e) {
    _dbInited = false;
    _dbInitRetryAt = Date.now();
    console.error("[ensureDb] error:", e?.message || e);
  }
}
