      var avColor = mAvColors[ri % mAvColors.length];
      var hiddenCls = ri >= 3 ? ' m-rv-hidden' : '';
      return '<div class="m-review-card'+hiddenCls+'">'
        +'<div class="m-review-avatar" style="background:'+avColor+'">'+initials+'</div>'
        +'<div class="m-review-body">'
