        var sess = parseInt(r.metricValues[0].value||0);
        var _mv1=r.metricValues&&r.metricValues[1]?r.metricValues[1]:null;var bounce = Math.round(parseFloat((_mv1?_mv1.value:0)||0)*100);
        var pct = Math.round(sess/landMax*100);
