// \u2500\u2500 \uAD6C\uAE00 \uB4DC\uB77C\uC774\uBE0C URL \uBCC0\uD658 \u2500\u2500
function convertGDriveUrl(url){
  var marker1 = 'drive.google.com/file/d/';
  var idx1 = url.indexOf(marker1);
  if(idx1 !== -1){
    var rest1 = url.slice(idx1 + marker1.length);
    var id1 = rest1.split('/')[0].split('?')[0];
    if(id1) return 'https://drive.google.com/uc?export=download&id=' + id1;
  }
  var marker2 = 'drive.google.com/open?id=';
  var idx2 = url.indexOf(marker2);
  if(idx2 !== -1){
    var id2 = url.slice(idx2 + marker2.length).split('&')[0];
    if(id2) return 'https://drive.google.com/uc?export=download&id=' + id2;
  }
  if(url.indexOf('drive.google.com/uc') !== -1) return url;
  return null;
}

function detectUrlType(url){
  if(!url) return null;
  if(url.indexOf('drive.google.com') !== -1) return 'gdrive';
  if(url.indexOf('r2.dev') !== -1 || url.indexOf('r2.cloudflarestorage') !== -1) return 'r2';
  var lower = url.toLowerCase().split('?')[0];
  if(lower.slice(-4)==='.mp4'||lower.slice(-5)==='.webm'||lower.slice(-4)==='.mov'||lower.slice(-4)==='.avi') return 'direct';
  if(url.indexOf('https://')===0 || url.indexOf('http://')===0) return 'url';
  return null;
}

function handleVideoUrlInput(raw){
  var badge = document.getElementById('vd-url-badge');
  var hint  = document.getElementById('vd-url-hint');
  var preview = document.getElementById('vd-url-preview');
  var input = document.getElementById('vd-url');
  if(!raw){ badge.style.display='none'; hint.style.display='none'; preview.style.display='none'; return; }
  var type = detectUrlType(raw);
  if(type === 'gdrive'){
    var converted = convertGDriveUrl(raw);
    if(converted){
      input.value = converted;
      badge.style.display='inline-block';
      badge.style.background='linear-gradient(135deg,#4285F4,#34A853)';
      badge.style.color='#fff';
      badge.textContent='\uAD6C\uAE00 \uB4DC\uB77C\uC774\uBE0C';
      hint.style.display='block';
      hint.textContent='\u2705 \uAD6C\uAE00 \uB4DC\uB77C\uC774\uBE0C \uB9C1\uD06C \uC790\uB3D9 \uBCC0\uD658 \uC644\uB8CC!';
      showVideoPreview(converted, preview);
      return;
    }
  }
  if(type === 'r2'){
    badge.style.display='inline-block';
    badge.style.background='linear-gradient(135deg,#F6821F,#FAAD3D)';
    badge.style.color='#fff';
    badge.textContent='Cloudflare R2';
    hint.style.display='none';
    showVideoPreview(raw, preview);
    return;
  }
  if(type === 'direct'){
    badge.style.display='inline-block';
    badge.style.background='linear-gradient(135deg,#9B59B6,#8E44AD)';
    badge.style.color='#fff';
    badge.textContent='MP4 \uB9C1\uD06C';
    hint.style.display='none';
    showVideoPreview(raw, preview);
    return;
  }
  badge.style.display='none';
  hint.style.display='none';
  preview.style.display='none';
}

function showVideoPreview(url, container){
  container.style.display='block';
  var wrap = document.createElement('div');
  var label = document.createElement('div');
  label.style.cssText = 'font-size:11px;color:rgba(255,255,255,.4);margin-bottom:4px';
  label.textContent = '\u25B6 \uBBF8\uB9AC\uBCF4\uAE30';
  var vid = document.createElement('video');
  vid.src = url;
  vid.controls = true;
  vid.style.cssText = 'width:100%;max-height:160px;border-radius:10px;background:#000;display:block';
  vid.onerror = function(){
    var errDiv = document.createElement('div');
    errDiv.style.cssText = 'padding:10px;background:rgba(239,68,68,.1);border:1px solid rgba(239,68,68,.3);border-radius:8px;font-size:12px;color:#f87171';
    errDiv.textContent = '\u26A0 \uC601\uC0C1\uC744 \uBD88\uB7EC\uC62C \uC218 \uC5C6\uC2B5\uB2C8\uB2E4. URL\uC744 \uD655\uC778\uD574\uC8FC\uC138\uC694.';
    while(container.firstChild) container.removeChild(container.firstChild);
    container.appendChild(label.cloneNode(true));
    container.appendChild(errDiv);
  };
  wrap.appendChild(label);
  wrap.appendChild(vid);
  while(container.firstChild) container.removeChild(container.firstChild);
  container.appendChild(wrap);
}

// \u2500\u2500 \uC601\uC0C1 \uD30C\uC77C \uC120\uD0DD \uCC98\uB9AC \u2500\u2500
var _selectedVideoFile = null;
window.handleVideoFileSelect = function(input) {
  var file = input.files[0];
  if(!file) return;
  _selectedVideoFile = file;

  // \uBBF8\uB9AC\uBCF4\uAE30
  var previewWrap = document.getElementById('vd-preview-wrap');
  var previewVideo = document.getElementById('vd-preview-video');
  var objectUrl = URL.createObjectURL(file);
  previewVideo.src = objectUrl;
  previewWrap.style.display = 'block';

  // \uB4DC\uB86D\uC874 \uD14D\uC2A4\uD2B8 \uBCC0\uACBD
  var dropZone = document.getElementById('vd-drop-zone');
  dropZone.innerHTML = '<i class="fas fa-check-circle" style="font-size:28px;color:#4ade80;margin-bottom:8px;display:block"></i>'
    + '<div style="font-size:13px;font-weight:700;color:#4ade80">' + file.name + '</div>'
    + '<div style="font-size:11px;color:rgba(255,255,255,.35);margin-top:4px">' + (file.size/1024/1024).toFixed(1) + 'MB \xB7 \uD074\uB9AD\uD558\uBA74 \uB2E4\uC2DC \uC120\uD0DD</div>';

  // \uB4F1\uB85D \uBC84\uD2BC \uD65C\uC131\uD654
  var btn = document.getElementById('vd-submit-btn');
  btn.style.opacity = '1';
  btn.style.pointerEvents = 'auto';
}

// \uB4DC\uB798\uADF8\uC564\uB4DC\uB86D
document.addEventListener('DOMContentLoaded', function(){
  var dz = document.getElementById('vd-drop-zone');
  if(!dz) return;
  dz.addEventListener('dragover', function(e){ e.preventDefault(); dz.style.borderColor='#FF4D8D'; dz.style.background='rgba(255,77,141,.08)'; });
  dz.addEventListener('dragleave', function(){ dz.style.borderColor='rgba(255,77,141,.4)'; dz.style.background='rgba(255,77,141,.03)'; });
  dz.addEventListener('drop', function(e){
    e.preventDefault();
    dz.style.borderColor='rgba(255,77,141,.4)'; dz.style.background='rgba(255,77,141,.03)';
    var file = e.dataTransfer.files[0];
    if(file && file.type.startsWith('video/')){
      var input = document.getElementById('vd-file-input');
      var dt = new DataTransfer(); dt.items.add(file); input.files = dt.files;
      window.handleVideoFileSelect(input);
    }
  });
});

// \u2500\u2500 \uC601\uC0C1 \uB4F1\uB85D (Cloudinary \uC5C5\uB85C\uB4DC \uD6C4 DB \uC800\uC7A5) \u2500\u2500
window.addVideo = async function addVideo(){
  if(!currentShopId){ alert('\uC5C5\uCCB4\uB97C \uBA3C\uC800 \uC120\uD0DD\uD574\uC8FC\uC138\uC694!'); return; }
  if(!_selectedVideoFile){ alert('\uC601\uC0C1 \uD30C\uC77C\uC744 \uC120\uD0DD\uD574\uC8FC\uC138\uC694!'); return; }

  var shop = shops.find(function(s){return s.id===currentShopId;})||{};
  var savedShopId = currentShopId;
  var btn = document.getElementById('vd-submit-btn');
  var progressWrap = document.getElementById('vd-progress-wrap');
  var progressBar = document.getElementById('vd-progress-bar');
  var progressPct = document.getElementById('vd-progress-pct');
  var progressLabel = document.getElementById('vd-progress-label');

  btn.disabled = true;
  btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> \uC5C5\uB85C\uB4DC \uC911...';
  progressWrap.style.display = 'block';

  try {
    // 1. \uC11C\uBA85 \uBC1C\uAE09
    progressLabel.textContent = '\uC5C5\uB85C\uB4DC \uC900\uBE44 \uC911...';
    var signRes = await fetch('/api/upload-sign');
    var sign = await signRes.json();

    // 2. Cloudinary\uC5D0 XHR\uB85C \uC5C5\uB85C\uB4DC (\uC9C4\uD589\uB960 \uD45C\uC2DC)
    progressLabel.textContent = 'Cloudinary\uC5D0 \uC5C5\uB85C\uB4DC \uC911...';
    var fd = new FormData();
    fd.append('file', _selectedVideoFile);
    fd.append('api_key', sign.apiKey);
    fd.append('timestamp', sign.timestamp);
    fd.append('signature', sign.signature);
    fd.append('folder', sign.folder);
    // eager \uBCC0\uD658 \uD3EC\uD568 (\uC5C5\uB85C\uB4DC \uC2DC 1\uD68C \uBCC0\uD658 \u2192 \uC774\uD6C4 \uD06C\uB798\uB527 \uC18C\uBAA8 \uC5C6\uC74C)
    if(sign.eager) fd.append('eager', sign.eager);

    var uploadResult = await new Promise(function(resolve, reject){
      var xhr = new XMLHttpRequest();
      xhr.open('POST', 'https://api.cloudinary.com/v1_1/' + sign.cloudName + '/video/upload');
      xhr.upload.onprogress = function(e){
        if(e.lengthComputable){
          var pct = Math.round(e.loaded/e.total*100);
          progressBar.style.width = pct + '%';
          progressPct.textContent = pct + '%';
        }
      };
      xhr.onload = function(){
        if(xhr.status === 200){
          resolve(JSON.parse(xhr.responseText));
        } else { reject(new Error('\uC5C5\uB85C\uB4DC \uC2E4\uD328: ' + xhr.status)); }
      };
      xhr.onerror = function(){ reject(new Error('\uB124\uD2B8\uC6CC\uD06C \uC624\uB958')); };
      xhr.send(fd);
    });

    var videoUrl = uploadResult.secure_url;
    // eager \uBCC0\uD658 URL \uCD94\uCD9C (low=360p, mid=480p, high=720p)
    var eagerArr = uploadResult.eager || [];
    var videoUrlLow  = (eagerArr[0] && eagerArr[0].secure_url) || '';
    var videoUrlMid  = (eagerArr[1] && eagerArr[1].secure_url) || '';
    var videoUrlHigh = (eagerArr[2] && eagerArr[2].secure_url) || '';

    // 3. DB \uC800\uC7A5
    progressLabel.textContent = '\uB4F1\uB85D \uC911...';
    progressBar.style.width = '100%';
    progressPct.textContent = '100%';

    var vdInst = (document.getElementById('vd-instagram')||{}).value||'';
    await fetch('/api/videos', {method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify({
      shopId: currentShopId,
      title: '',
      videoUrl: videoUrl,
      videoUrlLow: videoUrlLow,
      videoUrlMid: videoUrlMid,
      videoUrlHigh: videoUrlHigh,
      thumbnail: shop.thumbnail || '',
      description: '',
      tags: [],
      instagramUrl: vdInst.trim()
    })});

    _selectedVideoFile = null;
    closeVideoPanel();
    _shopExpanded[String(savedShopId)] = true;
    loadAll();

  } catch(e) {
    alert('\uC5C5\uB85C\uB4DC \uC2E4\uD328: ' + e.message);
    progressWrap.style.display = 'none';
    btn.disabled = false;
    btn.innerHTML = '<i class="fas fa-plus"></i> \uC601\uC0C1 \uB4F1\uB85D';
  }
}

